class Solution {
public:
    bool isPossible(vector<int>& nums) {
        unordered_map<int, int> count;
        for (int num : nums) {
            count[num]++;
        }

        for (int num : nums) {
            if (count[num] == 0) continue;
            int next = num + 1;
            int nextNext = num + 2;
            if (count[num] >= 3) {
                count[num] -= 3;
            } else if (count[num] > 0 && count[next] >= 1 && count[nextNext] >= 1) {
                count[num]--;
                count[next]--;
                count[nextNext]--;
            } else {
                return false;
            }
        }
        return true;
    }
};
